/*
	点击map以后， 对于词云做得操作
 */
function location_change(location=''){
	/*
		去除 svg.g 中所有元素
	 */
	if(!ready){
		return ;
	}
	
	// !! 有问题：works_index_list是按照location筛选的，词云显示的是相关地点为location的work的词云，但诗词是按照poems里面id直接找的
	let works_index_list = poems_filter(poems_withLocation, location);
	// console.log(works_index_list)
	// if(works_index_list.length === 0){
	// 	return;
	// }
	let poems_inLocation = data_filter(poems, keywords_2_workId[location]['works'], keywords_2_workId[location]['poems'])[1];
	// console.log(poems_inLocation)
	let keywords = [];
	poems_inLocation.forEach(d => {
		keywords = [...d['keywords'], ...keywords];
	})
	let keywords_dict = {};
	keywords.forEach(d => {
		if(!(d in keywords_dict)){
			keywords_dict[d] = 0;
		}
		keywords_dict[d] = keywords_dict[d]+1;
	})
	
	keywords = Object.entries(keywords_dict);
	keywords = keywords.sort(function(a, b){
		return b[1] - a[1];
	});
	// keywords = keywords.filter(val => val[0] in keywords_2_workId);
	keywords = keywords.slice(0, 50);
	
	keywords = keywords.map(entries => {return entries[0]});
	if(location in keywords_2_workId) {
		// console.log(location, keywords_2_workId[location]['average_score']);
		keywords.push(location);
		word_cloud_show(keywords);
		// if(selected_keywords.indexOf(location) === -1){
			
			// add_score_bar_show(keywords_2_workId[location]['average_score'], location);
			add_works_list_show(keywords_2_workId[location]['poems'], keywords_2_workId[location]['works'])
			selected_keywords.push(location);
			console.log(selected_keywords)
		// }
	} else {
		word_cloud_show(keywords);
	}
}


/*
	根据地点清洗poems数据，
 */
function poems_filter(poems, location){
	let poems2 = poems.filter(entries => entries[1]['location'].indexOf(location) > -1)
	let poems2_index = poems2.map(entries => entries[0]);
	
	return poems2_index;
}


/*
	导入数据后第一步，筛选需要的数据集
*/
function data_filter(data, work, poem){
	let res = {'work':{}, 'poem':{}};
	let res_all = [];
	let status = 0;
	for(let item of work){
		if(item in data['work']){
			res['work'][item] = data['work'][item];
			res_all.push(data['work'][item]);
		} else {
			status += 1;
		}
	}
	for(let item of poem){
		if(item in data['poem']){
			res['poem'][item] = data['poem'][item];
			res_all.push(data['poem'][item]);
		} else {
			status += 1;
		}
	}
	return [res, res_all, status];
}


/*
	计算筛选之后数据集的词频
	并筛选
*/
function calc_fre(cdata){
	let dict1 = {};
	let dict2 = {};
	for(let index of Object.keys(cdata['work'])){
		let work = cdata['work'][index];
		let keywords = work['keywords'];
		for(let keyword of keywords){
			if(!(keyword in dict1)){
				dict1[keyword] = 0;
			}
			dict1[keyword] += 1;
		}
	}
	for(let index of Object.keys(cdata['poem'])){
		let poem = cdata['poem'][index];
		let keywords = poem['keywords'];
		for(let keyword of keywords){
			if(!(keyword in dict1)){
				dict1[keyword] = 0;
			}
			dict1[keyword] += 1;
		}
	}
	for(let key of Object.keys(dict1)){
		let value = dict1[key];
		if(value >= 2){
			dict2[key] = value;
		}
	}
	
	return [dict2, dict1];
}


