/*
	去除情感打分svg
 */
function remove_score_bar_show(id, name){
	let nodeIndex = 0;
	let f1 = true;
	let score_g = d3.select('.chart2_bar').select('svg').select('g');
	let line_g = d3.select('.chart2_line').select('svg').select('g');
	let line_g_width = parseInt(d3.select('.chart2_line').select('svg').style('width').split('px')[0]);
	let score_g_width = parseInt(d3.select('.chart2_bar').select('svg').style('width').split('px')[0]);
	
	/*
		找到点击的圆的位置
	 */
	line_g.selectAll('circle').each(function(){
		if(f1 && d3.select(this).attr('id') !== id){
			nodeIndex += 1;
		} else {
			f1 = false;
		}
	});
	let index = 0;
	line_g.selectAll('circle').each(function(){
		if(index === nodeIndex){
			d3.select(this).remove();
		} else if(index < nodeIndex){
			d3.select(this)
				.transition()
				.duration(change_time)
				.ease(d3.easePolyInOut)
				.attr('cx', function(){
					return parseInt(d3.select(this).style('cx').split('px')[0])-line_g_width/10;
				});
		}
		index += 1;
	});
	index = 0;
	line_g.selectAll('text').each(function(){
		if(parseInt(index/2) === nodeIndex){
			d3.select(this).remove();
		} else if(parseInt(index/2) < nodeIndex){
			d3.select(this)
				.transition()
				.duration(change_time)
				.ease(d3.easePolyInOut)
				.attr('x', function(){
					return parseInt(d3.select(this).attr('x'))-line_g_width/10;
				});
		}
		index += 1;
	});
	index = 0;
	score_g.selectAll('rect').each(function(){
		if(index === nodeIndex){
			d3.select(this).remove();
		} else if(index < nodeIndex){
			d3.select(this)
				.transition()
				.duration(change_time)
				.ease(d3.easePolyInOut)
				.attr('x', function(){
					return parseInt(d3.select(this).style('x').split('px')[0])-score_g_width/10;
				});
		}
		index += 1;
	});
	delete selected_keywords[selected_keywords.indexOf(name)];
}


/*
	添加图书名单
 */
function add_works_list_show(l2, l1){
	[cur_poems, cur_poems_all, ...rest] = data_filter(poems, l1, l2);
	chart2_ul.selectAll("tr").remove();
	let table = chart2_ul.selectAll("tr")
		.data(cur_poems_all)
		.enter()
		.append("tr")
		.append("td")
		.attr("colspan", 3)
		.append("hr")
		.attr("border-color", "#909f9c")
		;
	let title = table.append("td")
		.attr('width', '30%')
		.append('li')
		.style('font-family', 'JinlingCu')
		.text(function(d){
			let {title, dynasty, author} = d;
			title = title.replace('《', '').replace('》', '');
			let text = `${title}`;	//`◆${title}`
			return text;
		})
		.append('li')
		.text(function(d){
			let {title, dynasty, author} = d;
			title = title.replace('《', '').replace('》', '');
			let text = ` - ${dynasty} ${author} - `;
			return text;
		});
	table.append("td")
		.attr('width', '2%');
	/*
		诗词内容 做到可以点击缩放
	 */
	let content_length = 22000000;
	table.append("td")
		.text(function(d){
			let {content} = d;
			
			if(content.length > content_length){
				return content.slice(0, content_length-3)+'...';
			}
			return content;
		})
		.on('click', function(e, d){
			d3.select(this)
				.text(function(){
					let {content} = d;
					let cur_content = d3.select(this).text();
					if(cur_content[cur_content.length-1] !== '.' && content.length > content_length){
						return content.slice(0, content_length-3)+'...';
					}
					return content;
				})
		});
}


/*
	词云生成
*/
function word_cloud_show(keywords){
	let instance = document.getElementsByClassName("chart2_wc")[0];
	let chart2 = echarts.getInstanceByDom(instance);
	if (chart2 == null) {
		chart2 = echarts.init(instance);
	}
	let maskImage = new Image();
	
	/*
	 石头, 鸡鸣, 雨花, 玄武, 金陵, 秦淮, 乌衣, 台城, 赏心, 钟山, 长干, 胭脂, 虎踞, 龙蟠,
	 六朝, 冶城, 新亭, 景阳, 辱井, 长干曲, 王谢, 堂前燕, 陈后主, 张丽华, 韩擒虎, 后庭花,
	 茉莉, 金粉, 针李, 中都，石头记，鸡鸣寺，雨花台，瞻园，夫子庙，明孝陵
（地名）丹阳、上元、孝陵、建邺、金陵、 秣陵、 南京、 建康、 建业、 江宁、 白下、 应天、 集庆
	 */
	
	// keywords = keywords.filter(val=>val in keywords_2_workId);
	let data = [];
	keywords.forEach(function(val){
		if(val in keywords_2_workId){
			data.push({
				name: val,
				value: keywords_2_workId[val]['total_count'],
				average_score: keywords_2_workId[val]['average_score'],
				poems: keywords_2_workId[val]['poems'],
				works: keywords_2_workId[val]['works'],
			});
		} else {
			let dataPoems = Object.entries(poems['work']).filter(function(entries){
				return entries[1]['keywords'].includes(val);
			});
			let dataWorks = Object.entries(poems['poem']).filter(function(entries){
				return entries[1]['keywords'].includes(val);
			});
			let value = dataPoems.length + dataWorks.length;
			let score = 0;
			dataPoems.forEach(function(entries){
				score += entries[1]['score']
			});
			dataWorks.forEach(function(entries){
				score += entries[1]['score']
			});
			if(value > 0) {
				data.push({
					name: val,
					value: value,
					average_score: score / value,
					poems: dataPoems.map(entries => entries[0]),
					works: dataWorks.map(entries => entries[0]),
				})
			}
		}
	});
	
	
	const wc_image = "data:image/png;base64,";
	maskImage.src = wc_image;
	
	chart2.setOption({
		series: [{
			type: 'wordCloud',
			left: 'center',
			top: 'center',
			width: '100%',
			height: '100%',
			right: null,
			bottom: null,
			sizeRange: [10, 60],
			// maskImage: maskImage,
			rotationRange: [0, 90],
			rotationStep: 90,
			gridSize: 3,
			drawOutOfBound: false,
			textStyle: {
				normal:{
					fontFamily: 'JinlingCu',
					fontWeight: 'normal',
					color: function(val){
						let {name} = val.data;
						if(core_keywords1.indexOf(name)>-1){
							return color[0]+"55";
						} else if(core_keywords2.indexOf(name)>-1){
							return color[1]+"55";
						} else {
							return color[0]+'55';
						}
					},
				}
			},
			data
		}]
	});
	chart2.on('click',function(params){
		let {average_score, name, poems, works} = params.data;
		if(selected_keywords.indexOf(name) === -1){
			selected_keywords.push(name);
			debounce(chart2_click_fun, 50, average_score, name, poems, works)();
		}
	});
}

function chart2_click_fun(score, name, poems, works){
	// add_score_bar_show(score, name);
	add_works_list_show(poems, works);
	timer = null;
}

/*
	 防抖函数
 */
let timer = null;
function debounce(fn, wait, ...rest){
	return function(){
		if(timer !== null){
			clearTimeout(timer);
		}
		timer = setTimeout(function(){fn(...rest)}, wait);
	}
}


function calculateSentimentScores(keywords_2_workId) {
    let sentimentScores = {};
    for (let location in keywords_2_workId) {
        sentimentScores[location] = keywords_2_workId[location]['average_score'];
    }
    return sentimentScores;
}

